const shell = require('shelljs');

/**
 * Extract the most recent N error logs from the specified log file and sort them by timestamp
 * @param {string} logFilePath - Path to the log file
 * @param {number} entryCount - Number of log entries to extract
 * @returns {Array} An array containing error logs, sorted by timestamp
 */
function extractRecentErrors(logFilePath, entryCount) {
  // Build the bash command
  const command = `grep 'ERROR' "${logFilePath}" | tail -n 100 | awk '{print $1,$2,$0}' | sort | tail -n ${entryCount}`;

  // Execute the command
  const result = shell.exec(command, { silent: true });

  // Check command execution result
  if (result.code !== 0) {
    throw new Error(`Command execution failed: ${result.stderr}`);
  }

  // Process output result
  const output = result.stdout.trim();
  if (!output) {
    return [];
  }

  // Split result by lines
  const lines = output.split('\n');

  // Since awk added extra timestamp fields, we need to return only the original log content
  return lines.map(line => {
    // Extract original log content (remove the first two timestamp fields)
    const parts = line.split(' ');
    if (parts.length >= 3) {
      return parts.slice(2).join(' ');
    }
    return line;
  });
}

module.exports = { extractRecentErrors };
```

